// Extract Calendly event data
const payload = $input.item.json.payload;
const invitee = payload;
const event = payload.scheduled_event || {};
const questions = payload.questions_and_answers || [];

// Map Calendly event type to our closer assignment
const eventName = event.name || '';
const isConsultoria = eventName.toLowerCase().includes('consultoria');
const isTelefonoRojo = eventName.toLowerCase().includes('telefono rojo');

// Extract question answers
function getAnswer(q, keyword) {
  const found = questions.find(qa => qa.question && qa.question.toLowerCase().includes(keyword.toLowerCase()));
  return found ? found.answer : null;
}

const nombre = invitee.name || '';
const email = invitee.email || '';

// Build lead object
const lead = {
  nombre: nombre,
  email: email,
  telefono: getAnswer(questions, 'telefono') || getAnswer(questions, 'whatsapp') || null,
  instagram: getAnswer(questions, 'instagram') || null,
  evento_calendly: eventName,
  calendly_event_id: event.uri ? event.uri.split('/').pop() : null,
  fecha_agendado: new Date().toISOString(),
  fecha_llamada: event.start_time || null,
  estado: 'pendiente',
  fuente: 'otro',
  // Ivan is the closer for these calendars
  closer_id: '9ddbc3a1-6a98-435e-baa1-bfeb23172317',
  // Extract setter from questions if available
  contexto_setter: getAnswer(questions, 'contexto') || getAnswer(questions, 'mensaje') || null,
  experiencia_ecommerce: getAnswer(questions, 'experiencia') || null,
  seguridad_inversion: getAnswer(questions, 'seguro') || null,
  tipo_productos: getAnswer(questions, 'producto') || null,
  compromiso_asistencia: getAnswer(questions, 'compromet') || null,
  dispuesto_invertir: getAnswer(questions, 'invertir') || getAnswer(questions, 'dispuest') || null,
  decisor: getAnswer(questions, 'decision') || getAnswer(questions, 'socio') || null,
};

return { json: lead };
